@register.simple_tag
def icon(name, size=20, css_class=""):
    """Render an inline SVG icon.

    Usage: {% load icons %}{% icon 'dashboard' 20 'h-5 w-5' %}
    """
    path = _ICONS.get(name)
    if path is None:
        path = _ICONS["box"]
    return mark_safe(
        f'<svg class="{css_class}" width="{size}" height="{size}" viewBox="0 0 24 24" '
        f'fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true">{path}</svg>'
    )
